/**
 * AlertLimitBar — Shows "3/3 alerts used" with progress bar and upgrade prompt.
 */
import { Link } from 'react-router-dom';
import useSignalTier from '../hooks/useSignalTier';
import { UPGRADE_PATH } from '../config/pricing';

const UPGRADE_MAP = {
  explorer: { nextTier: UPGRADE_PATH.explorer.nextLabel, price: UPGRADE_PATH.explorer.nextPrice, path: '/pricing-plans', nextMax: 25 },
  starter:  { nextTier: UPGRADE_PATH.starter.nextLabel,  price: UPGRADE_PATH.starter.nextPrice,  path: '/pricing-plans', nextMax: 50 },
  trader:   { nextTier: UPGRADE_PATH.trader.nextLabel,   price: UPGRADE_PATH.trader.nextPrice,   path: '/pricing-plans', nextMax: 'Unlimited' },
};

export default function AlertLimitBar({ currentCount }) {
  const { userTier, maxAlerts, delayColor, checkAlertLimit } = useSignalTier();
  const { allowed, max, remaining, isUnlimited } = checkAlertLimit(currentCount);

  // Don't show for unlimited tiers
  if (isUnlimited) return null;

  const pct = Math.min(100, (currentCount / max) * 100);
  const atLimit = !allowed;
  const nearLimit = pct >= 80;
  const upgrade = UPGRADE_MAP[userTier] || UPGRADE_MAP.explorer;

  const barColor = atLimit ? 'var(--color-red, #EF4444)'
    : nearLimit ? 'var(--color-amber, #D29922)'
    : 'var(--color-green, #22C55E)';

  return (
    <div
      style={{
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'space-between',
        gap: 16,
        flexWrap: 'wrap',
        padding: '12px 16px',
        marginBottom: 16,
        borderRadius: 8,
        background: atLimit ? 'rgba(239,68,68,0.06)' : 'var(--color-surface, #0F1620)',
        border: `1px solid ${atLimit ? 'rgba(239,68,68,0.25)' : 'var(--color-border, #1F2A37)'}`,
      }}
    >
      <div style={{ flex: 1, minWidth: 200 }}>
        <div style={{
          display: 'flex', alignItems: 'center', justifyContent: 'space-between',
          marginBottom: 6,
        }}>
          <span style={{
            fontSize: 13, fontWeight: 600,
            color: 'var(--color-text, #E5E7DB)',
            fontFamily: "'Plus Jakarta Sans', sans-serif",
          }}>
            {currentCount}/{max} alerts used
          </span>
          {remaining > 0 && (
            <span style={{
              fontSize: 11,
              color: 'var(--color-text-secondary, #8899AA)',
              fontFamily: "'JetBrains Mono', monospace",
            }}>
              {remaining} remaining
            </span>
          )}
        </div>
        {/* Progress bar */}
        <div style={{
          height: 4, borderRadius: 2,
          background: 'var(--color-surface-hover, #1A2332)',
          overflow: 'hidden',
        }}>
          <div style={{
            width: `${pct}%`,
            height: '100%',
            borderRadius: 2,
            background: barColor,
            transition: 'width 0.3s ease',
          }} />
        </div>
      </div>

      {atLimit && (
        <Link
          to={upgrade.path}
          style={{
            display: 'inline-flex',
            alignItems: 'center',
            gap: 4,
            padding: '8px 18px',
            borderRadius: 6,
            background: 'var(--color-amber, #D29922)',
            color: '#0B0F14',
            fontSize: 12,
            fontWeight: 700,
            fontFamily: "'Plus Jakarta Sans', sans-serif",
            textDecoration: 'none',
            whiteSpace: 'nowrap',
            transition: 'opacity 0.15s',
          }}
          onMouseEnter={(e) => { e.currentTarget.style.opacity = '0.85'; }}
          onMouseLeave={(e) => { e.currentTarget.style.opacity = '1'; }}
        >
          Upgrade to {upgrade.nextTier} ({upgrade.nextMax} alerts)
          <svg width="14" height="14" viewBox="0 0 24 24" fill="none"
            stroke="currentColor" strokeWidth="2.5" strokeLinecap="round">
            <path d="M5 12h14M12 5l7 7-7 7" />
          </svg>
        </Link>
      )}
    </div>
  );
}
