import { useState } from 'react'
import { apiPost } from '../utils/api'

const COLORS = {
  bg: '#0B0F14',
  surface: '#0F1620',
  border: '#1F2A37',
  text: '#E5E7DB',
  muted: '#90A3AF',
  green: '#22C55E',
  red: '#EF4444',
  blue: '#60A5FA',
}

const EXAMPLES = [
  'Alert me when AAPL RSI below 30',
  'Notify me if TSLA drops more than 5%',
  'Alert when NVDA MACD crosses signal line',
  'Ping me if BTC volume spikes above 2x average',
]

function mockParse(text) {
  const symbolMatch = text.match(/\b([A-Z]{2,5})\b/)
  const indicatorMatch = text.match(/\b(RSI|MACD|volume|price|Bollinger|MA|EMA|SMA|ATR)\b/i)
  const conditionMatch = text.match(/\b(below|above|crosses|drops|spikes|rises|exceeds|under|over)\b/i)
  const thresholdMatch = text.match(/(\d+(\.\d+)?)\s*(%|x)?/)

  return {
    symbol: symbolMatch ? symbolMatch[1] : 'UNKNOWN',
    indicator: indicatorMatch ? indicatorMatch[1].toUpperCase() : 'PRICE',
    condition: conditionMatch ? conditionMatch[1].toLowerCase() : 'below',
    threshold: thresholdMatch ? thresholdMatch[0] : '30',
    raw: text,
    confidence: symbolMatch && indicatorMatch && thresholdMatch ? 'high' : 'low',
  }
}

const conditionColors = {
  below: COLORS.red,
  above: COLORS.green,
  crosses: COLORS.blue,
  drops: COLORS.red,
  spikes: COLORS.green,
  rises: COLORS.green,
  exceeds: COLORS.green,
  under: COLORS.red,
  over: COLORS.green,
}

export default function NLAlertBuilder() {
  const [input, setInput] = useState('')
  const [parsed, setParsed] = useState(null)
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState(null)
  const [saved, setSaved] = useState(false)
  const [editMode, setEditMode] = useState(false)
  const [editedParsed, setEditedParsed] = useState(null)

  const handleParse = async () => {
    if (!input.trim()) return
    setLoading(true)
    setError(null)
    setParsed(null)
    setSaved(false)
    setEditMode(false)

    try {
      const data = await apiPost('/alerts/parse', { text: input })
      if (!data) throw new Error('API error')
      setParsed(data)
      setEditedParsed(data)
    } catch {
      const mock = mockParse(input)
      setParsed(mock)
      setEditedParsed(mock)
    } finally {
      setLoading(false)
    }
  }

  const handleKeyDown = (e) => {
    if (e.key === 'Enter') handleParse()
  }

  const handleConfirm = () => {
    setSaved(true)
    setEditMode(false)
  }

  const handleEdit = () => {
    setEditMode(true)
  }

  const displayParsed = editMode ? editedParsed : parsed
  const condColor = conditionColors[displayParsed?.condition] || COLORS.blue

  const styles = {
    card: {
      background: COLORS.surface,
      border: `1px solid ${COLORS.border}`,
      borderRadius: 14,
      padding: '20px 24px',
      fontFamily: "'JetBrains Mono', 'Fira Code', 'Courier New', monospace",
      color: COLORS.text,
      maxWidth: 540,
      width: '100%',
    },
    titleRow: {
      display: 'flex',
      alignItems: 'center',
      gap: 8,
      marginBottom: 16,
    },
    title: {
      fontSize: 14,
      fontWeight: 700,
      color: COLORS.text,
      letterSpacing: '0.04em',
    },
    inputRow: {
      display: 'flex',
      gap: 8,
      marginBottom: 12,
    },
    textInput: {
      flex: 1,
      background: COLORS.bg,
      border: `1px solid ${COLORS.border}`,
      borderRadius: 10,
      padding: '10px 14px',
      fontSize: 13,
      color: COLORS.text,
      fontFamily: 'inherit',
      outline: 'none',
    },
    parseBtn: {
      background: COLORS.blue,
      border: 'none',
      borderRadius: 10,
      color: '#0B0F14',
      fontFamily: 'inherit',
      fontWeight: 700,
      fontSize: 13,
      padding: '10px 16px',
      cursor: 'pointer',
      letterSpacing: '0.05em',
      whiteSpace: 'nowrap',
    },
    parseBtnDisabled: {
      opacity: 0.5,
      cursor: 'not-allowed',
    },
    examples: {
      display: 'flex',
      flexWrap: 'wrap',
      gap: 8,
      marginBottom: 16,
    },
    exampleChip: {
      background: COLORS.bg,
      border: `1px solid ${COLORS.border}`,
      borderRadius: 6,
      padding: '3px 8px',
      fontSize: 10,
      color: COLORS.muted,
      cursor: 'pointer',
      letterSpacing: '0.02em',
      transition: 'border-color 0.25s, color 0.25s',
    },
    divider: {
      borderTop: `1px solid ${COLORS.border}`,
      margin: '16px 0',
    },
    parsedCard: {
      background: COLORS.bg,
      border: `1px solid ${COLORS.border}`,
      borderRadius: 10,
      padding: '14px 16px',
      marginBottom: 16,
    },
    parsedHeader: {
      fontSize: 10,
      color: COLORS.muted,
      letterSpacing: '0.1em',
      textTransform: 'uppercase',
      marginBottom: 12,
    },
    fieldGrid: {
      display: 'grid',
      gridTemplateColumns: '1fr 1fr',
      gap: 12,
    },
    fieldBox: {
      background: COLORS.surface,
      border: `1px solid ${COLORS.border}`,
      borderRadius: 6,
      padding: '8px 12px',
    },
    fieldLabel: {
      fontSize: 10,
      color: COLORS.muted,
      letterSpacing: '0.08em',
      textTransform: 'uppercase',
      marginBottom: 4,
    },
    fieldValue: (highlight) => ({
      fontSize: 14,
      fontWeight: 700,
      color: highlight || COLORS.text,
    }),
    fieldInput: {
      background: 'transparent',
      border: 'none',
      borderBottom: `1px solid ${COLORS.border}`,
      color: COLORS.text,
      fontFamily: 'inherit',
      fontSize: 14,
      fontWeight: 700,
      width: '100%',
      outline: 'none',
      padding: '2px 0',
    },
    confidenceBadge: (level) => ({
      display: 'inline-flex',
      alignItems: 'center',
      gap: 4,
      background: level === 'high' ? `${COLORS.green}20` : `${COLORS.muted}20`,
      border: `1px solid ${level === 'high' ? COLORS.green : COLORS.muted}44`,
      borderRadius: 6,
      padding: '2px 8px',
      fontSize: 10,
      color: level === 'high' ? COLORS.green : COLORS.muted,
      marginTop: 12,
    }),
    actionRow: {
      display: 'flex',
      gap: 8,
    },
    confirmBtn: {
      flex: 1,
      background: COLORS.green,
      border: 'none',
      borderRadius: 10,
      color: '#0B0F14',
      fontFamily: 'inherit',
      fontWeight: 700,
      fontSize: 13,
      padding: '10px',
      cursor: 'pointer',
      letterSpacing: '0.05em',
    },
    editBtn: {
      flex: 1,
      background: 'transparent',
      border: `1px solid ${COLORS.border}`,
      borderRadius: 10,
      color: COLORS.muted,
      fontFamily: 'inherit',
      fontWeight: 700,
      fontSize: 13,
      padding: '10px',
      cursor: 'pointer',
      letterSpacing: '0.05em',
    },
    savedBanner: {
      background: `${COLORS.green}18`,
      border: `1px solid ${COLORS.green}44`,
      borderRadius: 10,
      padding: '10px 14px',
      fontSize: 13,
      color: COLORS.green,
      display: 'flex',
      alignItems: 'center',
      gap: 8,
    },
    loadingRow: {
      display: 'flex',
      alignItems: 'center',
      gap: 8,
      color: COLORS.muted,
      fontSize: 13,
    },
    spinner: {
      width: 14,
      height: 14,
      border: `2px solid ${COLORS.border}`,
      borderTopColor: COLORS.blue,
      borderRadius: '50%',
      animation: 'nl-spin 0.7s linear infinite',
    },
  }

  return (
    <div style={styles.card}>
      <style>{`
        @keyframes nl-spin {
          to { transform: rotate(360deg); }
        }
        .nl-example-chip:hover {
          border-color: ${COLORS.blue} !important;
          color: ${COLORS.blue} !important;
        }
        .nl-text-input:focus {
          border-color: ${COLORS.blue} !important;
        }
      `}</style>

      <div style={styles.titleRow}>
        <span style={{ fontSize: 16 }}>🔔</span>
        <span style={styles.title}>NATURAL LANGUAGE ALERT BUILDER</span>
      </div>

      <div style={styles.inputRow}>
        <input
          className="nl-text-input"
          style={styles.textInput}
          value={input}
          onChange={(e) => setInput(e.target.value)}
          onKeyDown={handleKeyDown}
          placeholder="e.g. Alert me when AAPL RSI below 30"
        />
        <button
          style={{
            ...styles.parseBtn,
            ...(loading || !input.trim() ? styles.parseBtnDisabled : {}),
          }}
          onClick={handleParse}
          disabled={loading || !input.trim()}
        >
          {loading ? '...' : 'PARSE'}
        </button>
      </div>

      <div style={styles.examples}>
        {EXAMPLES.map((ex) => (
          <span
            key={ex}
            className="nl-example-chip"
            style={styles.exampleChip}
            onClick={() => setInput(ex)}
          >
            {ex}
          </span>
        ))}
      </div>

      {loading && (
        <div style={styles.loadingRow}>
          <div style={styles.spinner} />
          Parsing alert...
        </div>
      )}

      {!loading && parsed && !saved && (
        <>
          <div style={styles.divider} />
          <div style={styles.parsedCard}>
            <div style={styles.parsedHeader}>Parsed Alert Preview</div>
            <div style={styles.fieldGrid}>
              <div style={styles.fieldBox}>
                <div style={styles.fieldLabel}>Symbol</div>
                {editMode ? (
                  <input
                    style={styles.fieldInput}
                    value={editedParsed.symbol}
                    onChange={(e) => setEditedParsed({ ...editedParsed, symbol: e.target.value })}
                  />
                ) : (
                  <div style={styles.fieldValue(COLORS.blue)}>{displayParsed.symbol}</div>
                )}
              </div>
              <div style={styles.fieldBox}>
                <div style={styles.fieldLabel}>Indicator</div>
                {editMode ? (
                  <input
                    style={styles.fieldInput}
                    value={editedParsed.indicator}
                    onChange={(e) => setEditedParsed({ ...editedParsed, indicator: e.target.value })}
                  />
                ) : (
                  <div style={styles.fieldValue()}>{displayParsed.indicator}</div>
                )}
              </div>
              <div style={styles.fieldBox}>
                <div style={styles.fieldLabel}>Condition</div>
                {editMode ? (
                  <input
                    style={styles.fieldInput}
                    value={editedParsed.condition}
                    onChange={(e) => setEditedParsed({ ...editedParsed, condition: e.target.value })}
                  />
                ) : (
                  <div style={styles.fieldValue(condColor)}>{displayParsed.condition}</div>
                )}
              </div>
              <div style={styles.fieldBox}>
                <div style={styles.fieldLabel}>Threshold</div>
                {editMode ? (
                  <input
                    style={styles.fieldInput}
                    value={editedParsed.threshold}
                    onChange={(e) => setEditedParsed({ ...editedParsed, threshold: e.target.value })}
                  />
                ) : (
                  <div style={styles.fieldValue()}>{displayParsed.threshold}</div>
                )}
              </div>
            </div>
            <div style={styles.confidenceBadge(parsed.confidence)}>
              <span>{parsed.confidence === 'high' ? '✓' : '!'}</span>
              <span>{parsed.confidence === 'high' ? 'High confidence parse' : 'Low confidence — review fields'}</span>
            </div>
          </div>

          <div style={styles.actionRow}>
            {editMode ? (
              <button style={styles.confirmBtn} onClick={() => { setParsed(editedParsed); setEditMode(false) }}>
                SAVE EDITS
              </button>
            ) : (
              <>
                <button style={styles.confirmBtn} onClick={handleConfirm}>
                  CONFIRM ALERT
                </button>
                <button style={styles.editBtn} onClick={handleEdit}>
                  EDIT
                </button>
              </>
            )}
          </div>
        </>
      )}

      {saved && (
        <>
          <div style={styles.divider} />
          <div style={styles.savedBanner}>
            <span>✓</span>
            <span>
              Alert saved: <strong>{parsed.symbol}</strong> {parsed.indicator} {parsed.condition} {parsed.threshold}
            </span>
          </div>
        </>
      )}
    </div>
  )
}
